/**
	 * Generate a JSON response given an array of data
	 *
	 * @since 2.1
	 * @param array $data the response data
	 * @return string
	 */
function generate_response( $data ) {
		if ( isset( $_GET['_jsonp'] ) ) {

			if ( ! apply_filters( 'woocommerce_api_jsonp_enabled', true ) ) {
				WC()->api->server->send_status( 400 );
				return wp_json_encode( array( array( 'code' => 'woocommerce_api_jsonp_disabled', 'message' => __( 'JSONP support is disabled on this site', 'woocommerce-legacy-rest-api' ) ) ) );
			}

			$jsonp_callback = $_GET['_jsonp'];

			if ( ! wp_check_jsonp_callback( $jsonp_callback ) ) {
				WC()->api->server->send_status( 400 );
				return wp_json_encode( array( array( 'code' => 'woocommerce_api_jsonp_callback_invalid', __( 'The JSONP callback function is invalid', 'woocommerce-legacy-rest-api' ) ) ) );
			}

			WC()->api->server->header( 'X-Content-Type-Options', 'nosniff' );

			// Prepend '/**/' to mitigate possible JSONP Flash attacks.
			// https://miki.it/blog/2014/7/8/abusing-jsonp-with-rosetta-flash/
			return '/**/' . $jsonp_callback . '(' . wp_json_encode( $data ) . ')';
		}

		return wp_json_encode( $data );
	}

/**
		 * Get database tables for current site
		 *
		 * @author Sofyan Sitorus <sofyan@artbees.net>
		 */
function get_tables() {
			global $wpdb;
			$exclude_tables = [
				$wpdb->base_prefix . 'users',
				$wpdb->base_prefix . 'usermeta',
				$wpdb->prefix . 'woocommerce_sessions',
				$wpdb->prefix . 'woocommerce_attribute_taxonomies',
			];
			$multi_site_tables = [
				$wpdb->base_prefix . 'blogs',
				$wpdb->base_prefix . 'blog_versions',
				$wpdb->base_prefix . 'signups',
				$wpdb->base_prefix . 'site',
				$wpdb->base_prefix . 'sitemeta',
				$wpdb->base_prefix . 'sitecategories',
				$wpdb->base_prefix . 'registration_log',
			];
			$current_site_tables = [];
			$current_blog_id     = get_current_blog_id();
			$tables              = $wpdb->get_results( 'SHOW FULL TABLES', ARRAY_N );
			foreach ( $tables as $table ) {
				if ( isset( $table[1] ) && 'VIEW' == $table[1] ) {
					continue;
				}

				if ( in_array( $table[0], $exclude_tables, true ) ) {
					continue;
				}

				if ( is_multisite() ) {
					if ( in_array( $table[0], $multi_site_tables, true ) ) {
						continue;
					}

					if ( is_main_site( $current_blog_id ) ) {
						$regex = '/^' . $wpdb->prefix . '([0-9])+/i';
						if ( preg_match( $regex, $table[0] ) ) {
							continue;
						}
					}

					if ( 0 === strpos( $table[0], $wpdb->prefix ) ) {
						$current_site_tables[] = $table[0];
					}
				} else {
					$current_site_tables[] = $table[0];
				}
			}

			return $current_site_tables;
		}

